:root {
    --primary: #2563eb;
    --primary-dark: #1d4ed8;
    --text: #1f2937;
    --bg: #f9fafb;
    --white: #ffffff;
    --border: #e5e7eb;
    --success: #16a34a;
    --warning: #f59e0b;
    --error: #dc2626;
}

* {
    box-sizing: border-box;
}

body {
    margin: 0;
    font-family: system-ui, -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Helvetica Neue", Arial, sans-serif;
    color: var(--text);
    background-color: var(--bg);
    line-height: 1.6;
}

.site-header {
    background-color: var(--white);
    border-bottom: 1px solid var(--border);
}

.navbar {
    max-width: 1200px;
    margin: 0 auto;
    padding: 1rem;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
    flex-wrap: wrap;
}

.brand {
    font-size: 1.5rem;
    font-weight: bold;
    color: var(--primary);
    text-decoration: none;
}

.nav-links {
    list-style: none;
    display: flex;
    gap: 1rem;
    margin: 0;
    padding: 0;
}

.nav-links a {
    color: var(--text);
    text-decoration: none;
}

.nav-links a:hover {
    color: var(--primary);
}

.nav-auth {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-wrap: wrap;
}

.nav-auth form {
    margin: 0;
}

.site-main {
    max-width: 1200px;
    margin: 0 auto;
    padding: 2rem 1rem;
    min-height: 60vh;
}

.site-footer {
    background-color: var(--white);
    border-top: 1px solid var(--border);
    text-align: center;
    padding: 1rem;
}

.footer-links {
    display: flex;
    justify-content: center;
    gap: 1rem;
    flex-wrap: wrap;
    margin-top: 0.5rem;
}

.footer-links a {
    color: var(--text);
    text-decoration: none;
}

.footer-links a:hover {
    color: var(--primary);
}

.hero {
    text-align: center;
    padding: 4rem 1rem;
    background: linear-gradient(135deg, #eff6ff 0%, #ffffff 100%);
    border-radius: 0.75rem;
    margin-bottom: 2rem;
}

.hero h1 {
    margin-top: 0;
    font-size: 2.5rem;
}

.hero-actions {
    display: flex;
    gap: 0.75rem;
    justify-content: center;
    flex-wrap: wrap;
}

.home-section {
    margin-bottom: 2rem;
}

.section-heading {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
    margin-bottom: 1rem;
}

.section-heading h2 {
    margin: 0;
}

.pill-list,
.teacher-cards {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    gap: 1rem;
}

.pill,
.teacher-card {
    background-color: var(--white);
    border: 1px solid var(--border);
    border-radius: 0.5rem;
    padding: 1rem;
}

.pill {
    text-align: center;
    color: var(--primary);
    text-decoration: none;
    font-weight: 600;
}

.teacher-card h3 {
    margin-top: 0;
}

.muted {
    color: #6b7280;
}

.features {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(250px, 1fr));
    gap: 1.5rem;
}

.feature {
    background-color: var(--white);
    padding: 1.5rem;
    border-radius: 0.5rem;
    border: 1px solid var(--border);
}

.btn {
    display: inline-block;
    padding: 0.75rem 1.5rem;
    border-radius: 0.375rem;
    text-decoration: none;
    font-weight: 500;
    cursor: pointer;
    border: none;
}

.btn-primary {
    background-color: var(--primary);
    color: var(--white);
}

.btn-primary:hover {
    background-color: var(--primary-dark);
}

.btn-secondary {
    background-color: var(--white);
    color: var(--primary);
    border: 1px solid var(--primary);
}

.btn-secondary:hover {
    background-color: #eff6ff;
}

.btn[disabled],
button[disabled] {
    cursor: wait;
    opacity: 0.7;
}

.messages {
    margin-bottom: 1rem;
    position: sticky;
    top: 0.5rem;
    z-index: 10;
}

.message {
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    margin-bottom: 0.5rem;
    border: 1px solid transparent;
    box-shadow: 0 6px 18px rgba(31, 41, 55, 0.08);
    transition: opacity 0.3s ease;
}

.message-success {
    background-color: #dcfce7;
    color: #166534;
    border-color: #86efac;
}

.message-error {
    background-color: #fee2e2;
    color: #991b1b;
    border-color: #fca5a5;
}

.message-warning {
    background-color: #fef3c7;
    color: #92400e;
    border-color: #fcd34d;
}

.message-info {
    background-color: #dbeafe;
    color: #1e40af;
    border-color: #93c5fd;
}

.page-content {
    background-color: var(--white);
    padding: 2rem;
    border-radius: 0.5rem;
    border: 1px solid var(--border);
}

.legal-page h2 {
    margin-top: 1.5rem;
}

.auth-form {
    max-width: 480px;
    margin: 0 auto;
}

.auth-form form p {
    margin-bottom: 1rem;
}

.auth-form label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
}

.auth-form input,
.auth-form select {
    width: 100%;
    padding: 0.5rem;
    border: 1px solid var(--border);
    border-radius: 0.375rem;
    font-size: 1rem;
}

.auth-form .errorlist {
    color: var(--error);
    list-style: none;
    padding: 0;
    margin: 0.25rem 0;
    font-size: 0.875rem;
}

.dashboard h1 {
    margin-top: 0;
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
    gap: 1rem;
    margin: 1.5rem 0;
}

.dashboard-card,
.status-card {
    background-color: #ffffff;
    border: 1px solid var(--border);
    border-radius: 0.5rem;
    padding: 1rem;
    margin-bottom: 1rem;
}

.status-approved {
    border-color: var(--success);
}

.status-pending {
    border-color: var(--warning);
}

.status-rejected,
.status-suspended {
    border-color: var(--error);
}

.item-list {
    list-style: none;
    padding: 0;
}

.item-list li {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 1rem;
    flex-wrap: wrap;
    border-bottom: 1px solid var(--border);
    padding: 0.75rem 0;
}

.review-form {
    margin-top: 1.5rem;
}

.review-form ul {
    list-style: none;
    padding: 0;
}

@media (max-width: 768px) {
    .navbar {
        flex-direction: column;
    }

    .nav-links {
        flex-wrap: wrap;
        justify-content: center;
    }

    .nav-auth {
        justify-content: center;
    }

    .hero {
        padding: 2.5rem 1rem;
    }

    .hero h1 {
        font-size: 2rem;
    }

    .section-heading {
        align-items: flex-start;
        flex-direction: column;
    }
}

@media (max-width: 480px) {
    .site-main {
        padding: 1rem;
    }

    .nav-links,
    .nav-auth,
    .hero-actions {
        flex-direction: column;
        width: 100%;
    }

    .nav-links li,
    .nav-auth a,
    .nav-auth form,
    .nav-auth button,
    .btn {
        width: 100%;
        text-align: center;
    }

    .page-content {
        padding: 1rem;
    }
}

